  1→//! Forth debugger component — COR24 emulator with Forth-aware inspection.
  2→
  3→use crate::config::{ForthTier, StackSize};
  4→use cor24_emulator::{AssembledLine, Assembler, EmulatorCore};
  5→use gloo::timers::callback::Timeout;
  6→use std::collections::{HashMap, VecDeque};
  7→use web_sys::{HtmlElement, HtmlInputElement};
  8→use yew::prelude::*;
  9→
 10→/// Execution batch size per tick (instructions).
 11→const BATCH_SIZE: u64 = 50_000;
 12→
 13→/// Tick interval in milliseconds.
 14→const TICK_MS: u32 = 25;
 15→
 16→/// Cell size in bytes (24-bit words).
 17→const CELL: u32 = 3;
 18→
 19→/// Bottom panel tab selection.
 20→#[derive(Clone, Copy, PartialEq, Eq)]
 21→enum BottomTab {
 22→    Dictionary,
 23→    CompileLog,
 24→}
 25→
 26→/// Categorized Forth word entry from assembler labels.
 27→#[derive(Clone)]
 28→struct DictEntry {
 29→    name: String,
 30→    addr: u32,
 31→    kind: WordKind,
 32→}
 33→
 34→#[derive(Clone, Copy, PartialEq, Eq)]
 35→enum WordKind {
 36→    Primitive,
 37→    ColonDef,
 38→    Thread,
 39→}
 40→
 41→pub enum Msg {
 42→    /// Load and start the emulator.
 43→    Init,
 44→    /// Run a batch of instructions.
 45→    Tick,
 46→    /// User typed in the input bar.
 47→    InputChanged(String),
 48→    /// User pressed Enter to send input.
 49→    SendInput,
 50→    /// Switch Forth tier.
 51→    SetTier(ForthTier),
 52→    /// Switch stack size.
 53→    SetStack(StackSize),
 54→    /// Reset emulator.
 55→    Reset,
 56→    /// Step one instruction.
 57→    Step,
 58→    /// Step over (run until return from call).
 59→    StepOver,
 60→    /// Toggle run/pause.
 61→    PauseResume,
 62→    /// Handle keydown in input field.
 63→    InputKeyDown(KeyboardEvent),
 64→    /// Toggle breakpoint at address.
 65→    ToggleBreakpoint(u32),
 66→    /// Select a dictionary word for inspection.
 67→    SelectWord(String),
 68→    /// Switch bottom panel tab (internal).
 69→    #[allow(private_interfaces)]
 70→    SetBottomTab(BottomTab),
 71→}
 72→
 73→pub struct Debugger {
 74→    emulator: EmulatorCore,
 75→    tier: ForthTier,
 76→    stack_size: StackSize,
 77→    output: String,
 78→    input: String,
 79→    running: bool,
 80→    halted: bool,
 81→    /// Pending timeout handle (kept alive to prevent cancel).
 82→    _tick_handle: Option<Timeout>,
 83→    /// Previous register values for change highlighting.
 84→    prev_regs: [u32; 8],
 85→    prev_pc: u32,
 86→    /// Pending UART RX bytes to feed one-at-a-time.
 87→    uart_rx_queue: VecDeque<u8>,
 88→    /// Ref to output div for auto-scroll.
 89→    output_ref: NodeRef,
 90→    /// Assembler labels: label name -> address.
 91→    labels: HashMap<String, u32>,
 92→    /// Reverse lookup: address -> label name.
 93→    reverse_labels: HashMap<u32, String>,
 94→    /// Assembled lines for compile log.
 95→    assembled_lines: Vec<AssembledLine>,
 96→    /// Categorized dictionary entries.
 97→    dict_entries: Vec<DictEntry>,
 98→    /// Currently selected word for inspection.
 99→    selected_word: Option<String>,
100→    /// Bottom panel tab.
101→    bottom_tab: BottomTab,
102→    /// Program extent (end of assembled code).
103→    program_end: u32,
104→}
105→
106→impl Debugger {
107→    fn load_binary(&mut self, _ctx: &Context<Self>) {
108→        let mut asm = Assembler::new();
109→        let result = asm.assemble(self.tier.assembly());
110→
111→        if !result.errors.is_empty() {
112→            self.output = "Assembly errors:\n".to_string();
113→            for e in &result.errors {
114→                self.output.push_str(e);
115→                self.output.push('\n');
116→            }
117→            return;
118→        }
119→
120→        // Store assembly metadata for panels.
121→        self.labels = result.labels.clone();
122→        self.reverse_labels = result
123→            .labels
124→            .iter()
125→            .map(|(name, &addr)| (addr, name.clone()))
126→            .collect();
127→        self.assembled_lines = result.lines.clone();
128→        self.program_end = result.bytes.len() as u32;
129→        self.dict_entries = self.build_dict_entries();
130→
131→        self.emulator.hard_reset();
132→        self.emulator.load_program(0, &result.bytes);
133→        self.emulator.load_program_extent(result.bytes.len() as u32);
134→        self.emulator.set_pc(0);
135→        self.output.clear();
136→        self.halted = false;
137→        self.prev_regs = [0; 8];
138→        self.prev_pc = 0;
139→        self.uart_rx_queue.clear();
140→        self.selected_word = None;
141→
142→        // Start paused — debugger mode.
143→        self.running = false;
144→        self.emulator.pause();
145→    }
146→
147→    fn schedule_tick(&mut self, ctx: &Context<Self>) {
148→        let link = ctx.link().clone();
149→        self._tick_handle = Some(Timeout::new(TICK_MS, move || {
