411→    fn update(&mut self, ctx: &Context<Self>, msg: Self::Message) -> bool {
412→        match msg {
413→            Msg::Init => {
414→                self.load_binary(ctx);
415→                true
416→            }
417→
418→            Msg::Tick => {
419→                if !self.running {
420→                    return false;
421→                }
422→
423→                self.prev_regs = self.snapshot_regs();
424→                self.prev_pc = self.emulator.snapshot().pc;
425→                self.feed_uart_byte();
426→
427→                let result = self.emulator.run_batch(BATCH_SIZE);
428→                self.collect_uart_output();
429→
430→                if self.emulator.is_halted() {
431→                    self.running = false;
432→                    self.halted = true;
433→                } else if matches!(result.reason, cor24_emulator::StopReason::Breakpoint(_)) {
434→                    self.running = false;
435→                    self.emulator.pause();
436→                } else if self.running {
437→                    self.schedule_tick(ctx);
438→                }
439→
440→                true
441→            }
442→
443→            Msg::InputChanged(val) => {
444→                self.input = val;
445→                false
446→            }
447→
448→            Msg::SendInput => {
449→                if self.input.is_empty() {
450→                    return false;
451→                }
452→                for b in self.input.bytes() {
453→                    self.uart_rx_queue.push_back(b);
454→                }
455→                self.uart_rx_queue.push_back(b'\n');
456→                self.input.clear();
457→
458→                if !self.running && !self.halted {
459→                    self.running = true;
460→                    self.emulator.resume();
461→                    self.schedule_tick(ctx);
462→                }
463→                true
464→            }
465→
466→            Msg::SetTier(tier) => {
467→                self.tier = tier;
468→                self.load_binary(ctx);
469→                true
470→            }
471→
472→            Msg::SetStack(size) => {
473→                self.stack_size = size;
474→                self.load_binary(ctx);
475→                true
476→            }
477→
478→            Msg::Reset => {
479→                self.load_binary(ctx);
480→                true
481→            }
482→
483→            Msg::Step => {
484→                if self.halted {
485→                    return false;
486→                }
487→                self.running = false;
488→                self.emulator.resume();
489→
490→                self.prev_regs = self.snapshot_regs();
491→                self.prev_pc = self.emulator.snapshot().pc;
492→
493→                self.feed_uart_byte();
494→                let _result = self.emulator.step();
495→                self.collect_uart_output();
496→
497→                self.emulator.pause();
498→                if self.emulator.is_halted() {
499→                    self.halted = true;
500→                }
501→                true
502→            }
503→
504→            Msg::StepOver => {
505→                if self.halted {
506→                    return false;
507→                }
508→                self.running = false;
509→                self.emulator.resume();
510→
511→                self.prev_regs = self.snapshot_regs();
512→                self.prev_pc = self.emulator.snapshot().pc;
513→
514→                self.feed_uart_byte();
515→                let _result = self.emulator.step_over();
516→                self.collect_uart_output();
517→
518→                self.emulator.pause();
519→                if self.emulator.is_halted() {
520→                    self.halted = true;
521→                }
522→                true
523→            }
524→
525→            Msg::PauseResume => {
526→                if self.halted {
527→                    return false;
528→                }
529→                if self.running {
530→                    self.running = false;
531→                    self.emulator.pause();
532→                    self._tick_handle = None;
533→                } else {
534→                    self.running = true;
535→                    self.emulator.resume();
536→                    self.schedule_tick(ctx);
537→                }
538→                true
539→            }
540→
541→            Msg::InputKeyDown(e) => {
542→                if e.key() == "Enter" {
543→                    ctx.link().send_message(Msg::SendInput);
544→                }
545→                false
546→            }
547→
548→            Msg::ToggleBreakpoint(addr) => {
549→                if self.emulator.has_breakpoint(addr) {
550→                    self.emulator.remove_breakpoint(addr);
551→                } else {
552→                    self.emulator.add_breakpoint(addr);
553→                }
554→                true
555→            }
556→
557→            Msg::SelectWord(name) => {
558→                if self.selected_word.as_ref() == Some(&name) {
559→                    self.selected_word = None; // toggle off
560→                } else {
561→                    self.selected_word = Some(name);
562→                }
563→                true
564→            }
565→
566→            Msg::SetBottomTab(tab) => {
567→                self.bottom_tab = tab;
568→                true
569→            }
570→        }
571→    }
